{
    Console.WriteLine($"Project: {w.GetNearestParent<Project>()?.Name ?? "unknown"}");
    Console.WriteLine($"Code: {w.Code}");
    Console.WriteLine($"Message: {w.Text}");
    Console.WriteLine("---");
}
EOF

